import { useState, useEffect } from 'react'
import { Save } from 'lucide-react'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Textarea } from '@/components/ui/textarea'
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card'
import { useToast } from '@/hooks/use-toast'
import { getEmailSettings, saveEmailSettings } from '@/lib/email'

export default function AdminEmails() {
  const [subject, setSubject] = useState('')
  const [body, setBody] = useState('')
  const { toast } = useToast()

  useEffect(() => {
    const settings = getEmailSettings()
    setSubject(settings.welcomeSubject)
    setBody(settings.welcomeBody)
  }, [])

  const handleSave = () => {
    saveEmailSettings({ welcomeSubject: subject, welcomeBody: body })
    toast({
      title: 'Configurações salvas',
      description: 'O template de e-mail foi atualizado com sucesso.',
    })
  }

  return (
    <div className="max-w-3xl animate-fade-in">
      <div className="mb-6">
        <h1 className="text-3xl font-heading font-bold mb-1">E-mails Automáticos</h1>
        <p className="text-muted-foreground">Configure as mensagens enviadas pelo sistema.</p>
      </div>

      <Card>
        <CardHeader>
          <CardTitle>E-mail de Boas-Vindas</CardTitle>
          <CardDescription>
            Enviado automaticamente para novos usuários cadastrados.
            <br className="mb-2" />
            Tags dinâmicas permitidas:{' '}
            <code className="bg-muted px-1 py-0.5 rounded text-xs">{'{{customer_name}}'}</code>,{' '}
            <code className="bg-muted px-1 py-0.5 rounded text-xs">{'{{coupon_code}}'}</code>,{' '}
            <code className="bg-muted px-1 py-0.5 rounded text-xs">
              {'{{discount_percentage}}'}
            </code>
          </CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="space-y-2">
            <Label htmlFor="subject">Assunto do E-mail</Label>
            <Input id="subject" value={subject} onChange={(e) => setSubject(e.target.value)} />
          </div>
          <div className="space-y-2">
            <Label htmlFor="body">Corpo da Mensagem</Label>
            <Textarea id="body" rows={8} value={body} onChange={(e) => setBody(e.target.value)} />
          </div>
          <Button onClick={handleSave}>
            <Save className="w-4 h-4 mr-2" />
            Salvar Alterações
          </Button>
        </CardContent>
      </Card>
    </div>
  )
}
